  1	import React, { FC, useRef, useState } from 'react';
  2	import { Updater } from 'use-immer';
  3	
  4	import {
  5	  Button,
  6	  FormFieldGroupExpandable,
  7	  FormFieldGroupHeader,
  8	  Tooltip,
  9	} from '@patternfly/react-core';
 10	import { MinusCircleIcon } from '@patternfly/react-icons';
 11	import { NodeNetworkConfigurationInterface, V1NodeNetworkConfigurationPolicy } from '@types';
 12	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
 13	
 14	import DeleteInterfaceModal from './DeleteInterfaceModal';
 15	import PolicyInterface, { onInterfaceChangeType } from './PolicyInterface';
 16	import { getExpandableTitle, isOVSBridgeExisting } from './utils';
 17	
 18	type PolicyInterfacesExpandableProps = {
 19	  policy: V1NodeNetworkConfigurationPolicy;
 20	  setPolicy: Updater<V1NodeNetworkConfigurationPolicy>;
 21	  createForm?: boolean;
 22	};
 23	
 24	const PolicyInterfacesExpandable: FC<PolicyInterfacesExpandableProps> = ({
 25	  policy,
 26	  setPolicy,
 27	  createForm,
 28	}) => {
 29	  const createdPolicy = useRef(createForm ? undefined : policy);
 30	
 31	  const createdInterfacesNames = createdPolicy?.current?.spec?.desiredState?.interfaces?.map(
 32	    (inFace) => inFace?.name,
 33	  );
 34	
 35	  const [interfaceToDelete, setInterfaceToDelete] = useState<NodeNetworkConfigurationInterface>();
 36	  const { t } = useNMStateTranslation();
 37	
 38	  const removeInterface = (interfaceIndex: number) => {
 39	    if (
 40	      createdInterfacesNames?.includes(policy?.spec?.desiredState?.interfaces[interfaceIndex]?.name)
 41	    ) {
 42	      return setInterfaceToDelete(policy.spec.desiredState.interfaces[interfaceIndex]);
 43	    }
 44	
 45	    setPolicy((draftPolicy) => {
 46	      (draftPolicy.spec.desiredState.interfaces as NodeNetworkConfigurationInterface[]).splice(
 47	        interfaceIndex,
 48	        1,
 49	      );
 50	      !isOVSBridgeExisting(draftPolicy) && delete draftPolicy.spec.desiredState.ovn;
 51	    });
 52	  };
 53	
 54	  return (
 55	    <>
 56	      {policy?.spec?.desiredState?.interfaces.map((policyInterface, index) => {
 57	        const interfaceCreated = createdInterfacesNames?.includes(policyInterface?.name);
 58	        return (
 59	          <FormFieldGroupExpandable
 60	            key={`${policyInterface.type}-${index}`}
 61	            className="policy-interface__expandable"
 62	            toggleAriaLabel={t('Details')}
 63	            isExpanded={true}
 64	            header={
 65	              <FormFieldGroupHeader
 66	                titleText={{
 67	                  text: getExpandableTitle(policyInterface, t),
 68	                  id: `nncp-interface-${index}`,
 69	                }}
 70	                actions={
 71	                  <Tooltip
 72	                    content={
 73	                      interfaceCreated
 74	                        ? t('Created interfaces cannot be removed')
 75	                        : t('Remove interface')
 76	                    }
 77	                  >
 78	                    <span>
 79	                      <Button
 80	                        variant="plain"
 81	                        aria-label={t('Remove')}
 82	                        isDisabled={Boolean(interfaceCreated)}
 83	                        onClick={() => removeInterface(index)}
 84	                      >
 85	                        <MinusCircleIcon />
 86	                      </Button>
 87	                    </span>
 88	                  </Tooltip>
 89	                }
 90	              />
 91	            }
 92	          >
 93	            <PolicyInterface
 94	              id={index}
 95	              isInterfaceCreated={Boolean(interfaceCreated)}
 96	              policyInterface={policyInterface}
 97	              onInterfaceChange={(updateInterface: onInterfaceChangeType) =>
 98	                setPolicy((draftPolicy) => {
 99	                  updateInterface(draftPolicy.spec.desiredState.interfaces[index], draftPolicy);
100	                })
101	              }
102	            />
103	          </FormFieldGroupExpandable>
104	        );
105	      })}
106	      {interfaceToDelete && (
107	        <DeleteInterfaceModal
108	          policyInterface={interfaceToDelete}
109	          isOpen={!!interfaceToDelete}
110	          closeModal={() => setInterfaceToDelete(undefined)}
111	          onSubmit={() => {
112	            setInterfaceToDelete(undefined);
113	          }}
114	        />
115	      )}
116	    </>
117	  );
118	};
119	
120	export default PolicyInterfacesExpandable;

