 3	import { cleanup, render } from '@testing-library/react';
 4	import { InterfaceType, NodeNetworkConfigurationInterface } from '@types';
 5	
 6	import { NETWORK_STATES } from '../constants';
 7	import PolicyInterface from '../PolicyInterface';
 8	
 9	afterEach(cleanup);
10	
11	const policyInterface: NodeNetworkConfigurationInterface = {
12	  name: 'br0',
13	  type: InterfaceType.LINUX_BRIDGE,
14	  state: NETWORK_STATES.Up,
15	};
16	
17	const onInterfaceChange = jest.fn();
18	
19	test('NNCPInterface', async () => {
20	  const { getByLabelText } = render(
21	    <PolicyInterface
22	      id={1}
23	      policyInterface={policyInterface}
24	      onInterfaceChange={onInterfaceChange}
25	    />,
26	  );
27	
28	  expect((getByLabelText('Interface name', { exact: false }) as HTMLInputElement).value).toBe(
29	    policyInterface.name,
30	  );
31	});

